"use strict";(globalThis.webpackChunkwebsite=globalThis.webpackChunkwebsite||[]).push([[720],{1232:(e,t,i)=>{i.r(t),i.d(t,{assets:()=>d,contentTitle:()=>a,default:()=>h,frontMatter:()=>o,metadata:()=>s,toc:()=>l});const s=JSON.parse('{"id":"training/part2-hands-on/virtual-token-service-vts--end-to-end-build","title":"32. Virtual Token Service (VTS) \u2014 End-to-End Build","description":"32.1 The Problem VTS Solves","source":"@site/docs/training/part2-hands-on/32-virtual-token-service-vts--end-to-end-build.md","sourceDirName":"training/part2-hands-on","slug":"/training/part2-hands-on/virtual-token-service-vts--end-to-end-build","permalink":"/rsapsdocumentation/docs/training/part2-hands-on/virtual-token-service-vts--end-to-end-build","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":32,"frontMatter":{"title":"32. Virtual Token Service (VTS) \u2014 End-to-End Build","sidebar_position":32},"sidebar":"docsSidebar","previous":{"title":"31. Lab Environment Options for Consultants","permalink":"/rsapsdocumentation/docs/training/part2-hands-on/lab-environment-options-for-consultants"},"next":{"title":"33. PCAP Deep Dive: The On-Premises Identity Portal","permalink":"/rsapsdocumentation/docs/training/part2-hands-on/pcap-deep-dive-the-on-premises-identity-portal"}}');var n=i(4848),r=i(8453);const o={title:"32. Virtual Token Service (VTS) \u2014 End-to-End Build",sidebar_position:32},a="32. Virtual Token Service (VTS) \u2014 End-to-End Build",d={},l=[{value:"32.1 The Problem VTS Solves",id:"321-the-problem-vts-solves",level:2},{value:"32.2 Server Side: Already Deployed",id:"322-server-side-already-deployed",level:2},{value:"32.3 Client Side: The Two-Step Builder Workflow",id:"323-client-side-the-two-step-builder-workflow",level:2},{value:"32.4 Mutual TLS (MTLS) Trust",id:"324-mutual-tls-mtls-trust",level:2},{value:"32.5 The Live Troubleshoot \u2014 A Diagnostic Case Study",id:"325-the-live-troubleshoot--a-diagnostic-case-study",level:2}];function c(e){const t={h1:"h1",h2:"h2",header:"header",li:"li",ol:"ol",p:"p",...(0,r.R)(),...e.components};return(0,n.jsxs)(n.Fragment,{children:[(0,n.jsx)(t.header,{children:(0,n.jsx)(t.h1,{id:"32-virtual-token-service-vts--end-to-end-build",children:"32. Virtual Token Service (VTS) \u2014 End-to-End Build"})}),"\n",(0,n.jsx)(t.h2,{id:"321-the-problem-vts-solves",children:"32.1 The Problem VTS Solves"}),"\n",(0,n.jsx)(t.p,{children:"Day 1 introduced VTS in a paragraph; Day 2 built it. The use case: non-persistent VDI environments. A software token requires a seed record distributed to the device \u2014 but a virtual desktop is re-imaged at every login, so nothing persists; pre-seeding is impossible. VTS sidesteps the seed entirely with an online distribution model: each time the user requests a code, the VTS client asks the AMS server, which places the user's token in lost mode, generates an emergency access code (EAC), and displays it in the client. The user authenticates with PIN + EAC. Every request is a fresh server round-trip \u2014 no persistent state on the desktop at all."}),"\n",(0,n.jsx)(t.h2,{id:"322-server-side-already-deployed",children:"32.2 Server Side: Already Deployed"}),"\n",(0,n.jsx)(t.p,{children:"VTS server capability ships inside AMS \u2014 Prime Quick Setup deploys it automatically. The only server artifact is vtsconfig.xml, specifying code duration and the number of codes displayed; it is almost never modified. One setting matters operationally: softwareOnly mode \u2014 when true (as in the demo, matching a real customer requirement), VTS refuses hardware tokens and serves only software-token holders."}),"\n",(0,n.jsx)(t.h2,{id:"323-client-side-the-two-step-builder-workflow",children:"32.3 Client Side: The Two-Step Builder Workflow"}),"\n",(0,n.jsxs)(t.ol,{children:["\n",(0,n.jsx)(t.li,{children:"Install the VTS Builder (admin tool) on one administrator machine. The builder is a configuration studio, not the end-user app: set the mode (virtual token), the MS URL (host without :8443 in the demo), the window title, prompt text (e.g., 'Enter SecurID PIN'), whether the PIN field displays, the help message (customers can point it at their own hosted article), and every error message \u2014 full white-label control."}),"\n",(0,n.jsx)(t.li,{children:"Build and distribute the end-user MSI. Clicking Build Now emits the final MSI package for end-user machines, pushed at scale via SCCM or the customer's standard software-distribution tooling. The build also emits a secret file that must be copied to the PrimeKit server under configs/MS/VTS packages (multiple secret files may coexist) \u2014 a server-side shared secret complementing the TLS trust."}),"\n"]}),"\n",(0,n.jsx)(t.h2,{id:"324-mutual-tls-mtls-trust",children:"32.4 Mutual TLS (MTLS) Trust"}),"\n",(0,n.jsx)(t.p,{children:"VTS client-server communication uses two-way SSL: the client validates the server certificate (standard), and the server validates a client certificate embedded in the MSI \u2014 because 'anybody can install this tool and request a certificate,' the client-side cert is what proves the request comes from an administrator-built package. Setup demonstrated with Keystore Explorer: generate a PFX (any CN \u2014 it exists purely for application trust), reference it in the builder, export the certificate chain, and import it into the MS trust store (truststore.jks) so the server trusts the client. Restart MS after placing the secret file and trust cert."}),"\n",(0,n.jsx)(t.h2,{id:"325-the-live-troubleshoot--a-diagnostic-case-study",children:"32.5 The Live Troubleshoot \u2014 A Diagnostic Case Study"}),"\n",(0,n.jsx)(t.p,{children:"The first end-to-end test failed ('rejecting my PIN'), and the trainer worked it exactly as he teaches:"}),"\n",(0,n.jsxs)(t.ol,{children:["\n",(0,n.jsx)(t.li,{children:"Checked the client-side view \u2014 nothing useful. Moved to the MS logs; the VTS log said 'no tokens found.'"}),"\n",(0,n.jsx)(t.li,{children:"Root cause #1 \u2014 identity mismatch. The VTS client does not prompt for a username; it reads the user ID from the Windows session automatically. The trainer was logged into Windows as one account while the token was assigned to the demo user. Fix: ensure the AM account matches the Windows session identity, with a token assigned and PIN set."}),"\n",(0,n.jsx)(t.li,{children:"Root cause #2 \u2014 token type. Still failing after the identity fix; cleared logs, reproduced, and read again: the assigned token was hardware, and softwareOnly=true in vtsconfig.xml excludes it. Fix: assign and distribute a software token, set its PIN \u2014 success; the EAC rendered in the client."}),"\n"]}),"\n",(0,n.jsx)(t.p,{children:"Operational details confirmed on success: the displayed code is valid for approximately three minutes per request (the user copies it into the authentication prompt), and prerequisites for any user are simply an assigned token and a pre-set PIN (set via self-service in advance). The trainer's closing frame doubled as reassurance: VTS is easy to deploy with several classic failure points, all of which announce themselves in the logs \u2014 and recordings of this exact build exist for reference when consultants hit them in the field."})]})}function h(e={}){const{wrapper:t}={...(0,r.R)(),...e.components};return t?(0,n.jsx)(t,{...e,children:(0,n.jsx)(c,{...e})}):c(e)}},8453:(e,t,i)=>{i.d(t,{R:()=>o,x:()=>a});var s=i(6540);const n={},r=s.createContext(n);function o(e){const t=s.useContext(r);return s.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function a(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(n):e.components||n:o(e.components),s.createElement(r.Provider,{value:t},e.children)}}}]);